import machine
import time
import network
from umqtt.simple import MQTTClient

# Wi-Fi credentials
WIFI_SSID = "YOUR_WIFI_SSID"
WIFI_PASSWORD = "YOUR_WIFI_PASSWORD"

# MQTT broker details
MQTT_BROKER_IP = "YOUR_MQTT_BROKER_IP"  # e.g., "192.168.1.100" or "broker.hivemq.com"
MQTT_CLIENT_ID = "esp32_sensor_client"
MQTT_TOPIC = "sensors/temp"

# Sensor reading interval (seconds)
PUBLISH_INTERVAL_SECONDS = 60

# --- Wi-Fi Connection ---
def connect_wifi():
    print("Connecting to WiFi...")
    sta_if = network.WLAN(network.STA_IF)
    if not sta_if.isconnected():
        sta_if.active(True)
        sta_if.connect(WIFI_SSID, WIFI_PASSWORD)
        while not sta_if.isconnected():
            time.sleep(1)
            print(".", end="")
    print("\nWiFi connected:", sta_if.ifconfig())
    return sta_if.isconnected()

# --- Simulate Sensor Reading ---
# In a real application, you would read from an actual sensor (e.g., DHT11, DS18B20)
def read_temperature():
    # Simulate a temperature reading between 20.0 and 30.0 degrees Celsius
    return 20.0 + (time.time() % 100) / 10.0 # Just a fluctuating value for demonstration

# --- Main Program ---
def main():
    if not connect_wifi():
        print("Failed to connect to WiFi. Exiting.")
        return

    mqtt_client = None
    try:
        print(f"Connecting to MQTT broker: {MQTT_BROKER_IP}")
        mqtt_client = MQTTClient(MQTT_CLIENT_ID, MQTT_BROKER_IP)
        mqtt_client.connect()
        print("Connected to MQTT broker.")
    except Exception as e:
        print(f"Failed to connect to MQTT broker: {e}")
        time.sleep(5) # Wait before retrying in a real loop
        machine.reset() # Simple reset for critical failure, reconsider for production

    while True:
        try:
            temperature = read_temperature()
            msg = f"{temperature:.2f}"
            print(f"Publishing to topic '{MQTT_TOPIC}': {msg}")
            mqtt_client.publish(MQTT_TOPIC, msg)
            print("Message published.")
        except OSError as e:
            print(f"MQTT publish failed: {e}. Reconnecting...")
            try:
                mqtt_client.disconnect()
                mqtt_client.connect()
                print("Reconnected to MQTT broker.")
            except Exception as reconnect_e:
                print(f"Failed to reconnect to MQTT broker: {reconnect_e}")
                time.sleep(5)
                machine.reset() # Reset if reconnection fails

        time.sleep(PUBLISH_INTERVAL_SECONDS)

if __name__ == "__main__":
    main()